// Return the response data as-is
const response = $input.first().json;
return response;

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_labels',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not update service labels' }
};

// Erro de validação
const input = $input.first().json;
return {
  statusCode: input.statusCode || 400,
  body: input.body || { ok: false, error: 'Validation failed' }
};

// Conta registros afetados e constrói resposta
const affectedRecords = $input.all()
  .filter(item => item.json && item.json.codigo_servico)
  .length;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_labels',
  event: 'service_labels_upserted',
  labels_updated: affectedRecords,
  level: 'info'
}));

// statusCode 201 — preserva compatibilidade com Flask original
return {
  statusCode: 201,
  body: {
    message: 'Service labels updated successfully',
    labels_updated: affectedRecords
  }
};

// Transform e normaliza dados dos labels de serviço
// Expande cada label para um item separado
const ctx = $input.first().json;
const labels = ctx.labels;

// Decode HTML entities function (reutilizada)
function decodeHtml(obj) {
  if (typeof obj === 'string') {
    return obj
      .replace(/&amp;/g,  '&')
      .replace(/&lt;/g,   '<')
      .replace(/&gt;/g,   '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g,  "'")
      .replace(/&#x27;/g, "'")
      .replace(/&#x2F;/g, '/')
      .replace(/&nbsp;/g, ' ');
  }
  if (Array.isArray(obj)) return obj.map(decodeHtml);
  if (typeof obj === 'object' && obj !== null) {
    const out = {};
    for (const k in obj) out[k] = decodeHtml(obj[k]);
    return out;
  }
  return obj;
}

const decodedLabels = decodeHtml(labels);

const transformedLabels = decodedLabels.map((label, index) => {
  const codigo = String(label.codigo || label.Codigo || label.CodigoServico || '').trim();

  if (!codigo) {
    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      route: 'nf_service_labels',
      event: 'label_skipped_no_codigo',
      label_index: index,
      label_data: label,
      level: 'warn'
    }));
    return null;
  }

  return {
    codigo_servico: codigo,
    descricao: String(label.descricao || label.Descricao || label.Nome || '').trim(),
    aliquota_iss: parseFloat(String(label.aliquota_iss || label.AliquotaISS || label.Aliquota || '0').replace(',', '.')) || 0,
    ativo: Boolean(label.ativo !== undefined ? label.ativo : label.Ativo !== undefined ? label.Ativo : true),
    observacoes: String(label.observacoes || label.Observacoes || label.Obs || '').trim()
  };
}).filter(label => label !== null);

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_labels',
  event: 'labels_transformed',
  valid_labels: transformedLabels.length,
  total_input: decodedLabels.length,
  level: 'info'
}));

return transformedLabels;

// ─────────────────────────────────────────────
// VHSYS :: nf_service_labels
// Rota   : POST /nf_service_labels
// Fase 5 : Fluxos NF
// ─────────────────────────────────────────────
// Input  : { data: { labels: [{ codigo, descricao, ... }] } }
// Output : { message: 'Service labels updated successfully', labels_updated: number } HTTP 201
// Banco  : UPSERT nf_service_labels por codigo
// Chave  : codigo_servico
// ─────────────────────────────────────────────

const body = $input.first().json.body || $input.first().json;

if (!body.data) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing required field: data' }
  };
}

if (!body.data.labels || !Array.isArray(body.data.labels)) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing or invalid labels array' }
  };
}

const labels = body.data.labels;

if (labels.length === 0) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Labels array cannot be empty' }
  };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_labels',
  event: 'input_validated',
  labels_count: labels.length,
  level: 'info'
}));

return { _valid: true, labels };
